class RestrictedUnpickler(pickle.Unpickler):
    """
    A restricted unpickler that only allows safe modules/classes.
    This prevents arbitrary code execution via crafted pickle files.
    """

    ALLOWED_MODULES_CLASSES = {
        "sklearn",
        "numpy",
        "numpy.core",
        "numpy.core.multiarray",
        "scipy",
        "xgboost",
        "lightgbm",
        "collections",
        "builtins",
        "copy_reg",
        "_codecs",
        "encodings",
    }

    BLOCKED_NAMES = {
        "exec",
        "eval",
        "compile",
        "__import__",
        "getattr",
        "setattr",
        "delattr",
        "globals",
        "locals",
        "vars",
        "open",
        "input",
        "breakpoint",
    }

    BLOCKED_MODULES = {
        "os",
        "subprocess",
        "sys",
        "shutil",
        "socket",
        "http",
        "urllib",
        "requests",
        "ctypes",
        "importlib",
        "code",
        "codeop",
        "compileall",
        "commands",
        "pdb",
        "profile",
        "trace",
        "webbrowser",
        "antigravity",
        "turtle",
        "signal",
        "multiprocessing",
        "threading",
        "pty",
        "pipes",
        "posixpath",
        "ntpath",
        "tempfile",
        "glob",
        "fnmatch",
        "pathlib",
        "fileinput",
        "io",
        "pickle",
        "_pickle",
        "shelve",
        "marshal",
        "dbm",
        "sqlite3",
        "zipfile",
        "tarfile",
        "gzip",
        "bz2",
        "lzma",
        "zipimport",
        "runpy",
    }

    def find_class(self, module: str, name: str):
        # Block dangerous modules entirely
        top_module = module.split(".")[0]
        if top_module in self.BLOCKED_MODULES:
            raise pickle.UnpicklingError(
                f"Blocked module in pickle stream: {module}"
            )

        # Block dangerous builtins by name
        if name in self.BLOCKED_NAMES:
            raise pickle.UnpicklingError(
                f"Blocked callable in pickle stream: {module}.{name}"
            )

        # Only allow known-safe module families
        is_allowed = any(
            module == allowed or module.startswith(allowed + ".")
            for allowed in self.ALLOWED_MODULES_CLASSES
        )
        if not is_allowed:
            raise pickle.UnpicklingError(
                f"Module not in allowlist: {module}.{name}"
            )

        return super().find_class(module, name)


def _compute_sha256(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def _scan_pickle_safety(data: bytes) -> Dict[str, Any]:
    """
    Perform a static analysis of the pickle byte-stream *before* loading.
    Returns a dict with 'safe' (bool) and 'issues' (list[str]).
    """
    issues: list[str] = []

    # ---- lightweight opcode scan (no third-party dep required) ----
    DANGEROUS_OPCODES = {
        b"R",   # REDUCE  – call a callable
        b"\x81",  # NEWOBJ
        b"\x92",  # NEWOBJ_EX
        b"i",   # INST
        b"o",   # OBJ
        b"\x83",  # STACK_GLOBAL (Py3.8+)
    }

    # Quick scan for GLOBAL / STACK_GLOBAL referencing dangerous modules
    DANGEROUS_MODULE_PREFIXES = (
        b"os", b"subprocess", b"sys", b"shutil", b"socket",
        b"http", b"urllib", b"requests", b"ctypes", b"importlib",
        b"builtins\nexec", b"builtins\neval", b"builtins\n__import__",
        b"builtins\ngetattr", b"builtins\nopen",
        b"nt", b"posix", b"commands", b"pdb",
    )

    for prefix in DANGEROUS_MODULE_PREFIXES:
        if prefix in data:
            issues.append(
                f"Potentially dangerous reference found in byte-stream: {prefix!r}"
            )

    # ---- optional deep analysis via fickling (if installed) ----
    try:
        from fickling.pickle import Pickled
        pickled = Pickled.load(io.BytesIO(data))
        # fickling can detect calls to os.system, eval, exec, etc.
        for node in pickled:
            node_str = str(node)
            for kw in ("os.", "subprocess", "exec", "eval", "system",
                        "__import__", "builtins.open"):
                if kw in node_str:
                    issues.append(f"Fickling detected dangerous node: {node_str[:200]}")
    except ImportError:
        pass  # fickling not installed; rely on opcode scan above
    except Exception:
        issues.append("Fickling analysis failed; treat with caution.")

    return {
        "safe": len(issues) == 0,
        "issues": issues,
    }


def safe_load_model(data: bytes):
    """Deserialize a model using the restricted unpickler."""
    return RestrictedUnpickler(io.BytesIO(data)).load()


