@app.post("/models/upload", response_model=ModelInfo)
async def upload_model(
    file: UploadFile = File(...),
    tenant_id: str = Header(..., alias="X-Tenant-ID"),
    description: Optional[str] = Form(None),
):
    """
    Upload a serialized (pickle) model file.
    The file undergoes safety scanning before being accepted.
    """
    # --- basic validation ---
    if not file.filename:
        raise HTTPException(status_code=400, detail="No filename provided.")

    contents = await file.read()

    if len(contents) > MAX_MODEL_SIZE:
        raise HTTPException(
            status_code=413,
            detail=f"Model file exceeds maximum size of {MAX_MODEL_SIZE} bytes.",
        )

    if len(contents) == 0:
        raise HTTPException(status_code=400, detail="Uploaded file is empty.")

    file_hash = _compute_sha256(contents)

    # --- static safety scan ---
    scan_result = _scan_pickle_safety(contents)
    if not scan_result["safe"]:
        raise HTTPException(
            status_code=422,
            detail={
                "message": "Model file failed safety scan and was rejected.",
                "issues": scan_result["issues"],
            },
        )

    # --- deserialize with restricted unpickler ---
    try:
        model = safe_load_model(contents)
    except pickle.UnpicklingError as exc:
        raise HTTPException(
            status_code=422,
            detail=f"Model deserialization blocked by safety policy: {exc}",
        )
    except Exception as exc:
        raise HTTPException(
            status_code=400,
            detail=f"Failed to load model: {exc}",
        )

    # --- store model ---
    model_id = str(uuid.uuid4())
    now = datetime.utcnow().isoformat()

    # Persist raw bytes to disk (optional, for reload)
    model_path = os.path.join(UPLOAD_DIR, f"{model_id}.pkl")
    with open(model_path, "wb") as f:
        f.write(contents)

    model_store[model_id] = {
        "model": model,
        "tenant_id": tenant_id,
        "filename": file.filename,
        "description": description,
        "uploaded_at": now,
        "file_hash": file_hash,
        "model_path": model_path,
    }

    return ModelInfo(
        model_id=model_id,
        tenant_id=tenant_id,
        filename=file.filename,
        uploaded_at=now,
        file_hash=file_hash,
        status="ready",
    )


@app.post("/models/predict")
async def predict(
    request: InferenceRequest,
    tenant_id: str = Header(..., alias="X-Tenant-ID"),
):
    """
    Run inference on an uploaded model.
    Enforces tenant isolation – a tenant may only use their own models.
    """
    model_id = request.model_id
    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found.")

    entry = model_store[model_id]

    # Tenant isolation
    if entry["tenant_id"] != tenant_id:
        raise HTTPException(
            status_code=403,
            detail="Access denied: model belongs to a different tenant.",
        )

    model = entry["model"]

    # Prepare input
    try:
        input_array = np.array(request.input_data)
        if input_array.ndim == 1:
            input_array = input_array.reshape(1, -1)
    except Exception as exc:
        raise HTTPException(
            status_code=400,
            detail=f"Invalid input data: {exc}",
        )

    # Run prediction
    try:
        if hasattr(model, "predict"):
            predictions = model.predict(input_array)
        elif callable(model):
            predictions = model(input_array)
        else:
            raise HTTPException(
                status_code=400,
                detail="Uploaded object does not support prediction.",
            )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Inference failed: {exc}",
        )

    # Convert numpy types for JSON serialization
    if isinstance(predictions, np.ndarray):
        predictions = predictions.tolist()

    return {"model_id": model_id, "predictions": predictions}


@app.get("/models", response_model=list[ModelInfo])
async def list_models(
    tenant_id: str = Header(..., alias="X-Tenant-ID"),
):
    """List all models belonging to the requesting tenant."""
    results = []
    for mid, entry in model_store.items():
        if entry["tenant_id"] == tenant_id:
            results.append(
                ModelInfo(
                    model_id=mid,
                    tenant_id=entry["tenant_id"],
                    filename=entry["filename"],
                    uploaded_at=entry["uploaded_at"],
                    file_hash=entry["file_hash"],
                    status="ready",
                )
            )
    return results


@app.get("/models/{model_id}", response_model=ModelInfo)
async def get_model(
    model_id: str,
    tenant_id: str = Header(..., alias="X-Tenant-ID"),
):
    """Get metadata for a specific model (tenant-scoped)."""
    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found.")

    entry = model_store[model_id]
    if entry["tenant_id"] != tenant_id:
        raise HTTPException(status_code=403, detail="Access denied.")

    return ModelInfo(
        model_id=model_id,
        tenant_id=entry["tenant_id"],
        filename=entry["filename"],
        uploaded_at=entry["uploaded_at"],
        file_hash=entry["file_hash"],
        status="ready",
    )


@app.delete("/models/{model_id}")
async def delete_model(
    model_id: str,
    tenant_id: str = Header(..., alias="X-Tenant-ID"),
):
    """Delete a model (tenant-scoped)."""
    if model_id not in model_store:
        raise HTTPException(status_code=404, detail="Model not found.")

    entry = model_store[model_id]
    if entry["tenant_id"] != tenant_id:
        raise HTTPException(status_code=403, detail="Access denied.")

    # Remove file from disk
    model_path = entry.get("model_path")
    if model_path and os.path.exists(model_path):
        os.remove(model_path)

    del model_store[model_id]
    return {"detail": "Model deleted.", "model_id": model_id}


@app.get("/health")
async def health():
    return {"status": "healthy", "models_loaded": len(model_store)}


